from dataclasses import dataclass
import time

from langchain_groq import ChatGroq
from langchain_core.messages import HumanMessage, SystemMessage

# ------------------------------------------------------------
# Configure Groq
# ------------------------------------------------------------

GROQ_API_KEY = os.getenv("GROQ_API_KEY")

llm = ChatGroq(
    model="llama-3.3-70b-versatile",
    api_key=GROQ_API_KEY,
    temperature=0
)

# Groq pricing (optional)
COST_INPUT = 0.59 / 1_000_000
COST_OUTPUT = 0.79 / 1_000_000

# ------------------------------------------------------------
# Result Dataclass
# ------------------------------------------------------------

@dataclass
class RAGResult:
    answer: str
    sources: list
    embed_ms: float
    retrieve_ms: float
    generate_ms: float
    input_tokens: int = 0
    output_tokens: int = 0

    @property
    def total_ms(self):
        return (
            self.embed_ms
            + self.retrieve_ms
            + self.generate_ms
        )

    @property
    def cost_usd(self):
        return (
            self.input_tokens * COST_INPUT
            + self.output_tokens * COST_OUTPUT
        )

# ------------------------------------------------------------
# Main RAG Function
# ------------------------------------------------------------

def rag_answer(query: str) -> RAGResult:

    # --------------------------------------------------------
    # Stage 1: Query Embedding
    # --------------------------------------------------------

    t0 = time.perf_counter()

    _ = embedder.embed_query(query)

    embed_ms = (
        time.perf_counter() - t0
    ) * 1000

    # --------------------------------------------------------
    # Stage 2: Azure Hybrid Retrieval
    # --------------------------------------------------------

    t0 = time.perf_counter()

    raw = azure_hybrid_search(query)

    retrieve_ms = (
        time.perf_counter() - t0
    ) * 1000

    context = "\n\n".join(
        [
            f"[{r['title']}]\n{r['content']}"
            for r in raw
        ]
    )

    sources = list(
        {
            r["title"]
            for r in raw
        }
    )

    # --------------------------------------------------------
    # Stage 3: Groq Generation
    # --------------------------------------------------------

    messages = [
        SystemMessage(
            content=(
                "Answer ONLY from the provided context. "
                "If the answer is not present in the context, "
                "say that the information is unavailable. "
                "Be concise."
            )
        ),
        HumanMessage(
            content=f"{context}\n\nQuestion: {query}"
        )
    ]

    t0 = time.perf_counter()

    response = llm.invoke(messages)

    generate_ms = (
        time.perf_counter() - t0
    ) * 1000

    # --------------------------------------------------------
    # Token Usage
    # --------------------------------------------------------

    usage = response.response_metadata.get(
        "token_usage",
        {}
    )

    return RAGResult(
        answer=response.content,
        sources=sources,
        embed_ms=embed_ms,
        retrieve_ms=retrieve_ms,
        generate_ms=generate_ms,
        input_tokens=usage.get(
            "prompt_tokens",
            0
        ),
        output_tokens=usage.get(
            "completion_tokens",
            0
        )
    )

# ------------------------------------------------------------
# Smoke Test
# ------------------------------------------------------------

test = rag_answer(
    "What is retrieval-augmented generation?"
)

print("RAG pipeline smoke test passed!")
print()

